import { useState } from 'react';
import './App.css';

// ─── Data ────────────────────────────────────────────────────────────────────

const GROUPS = {
  A: ['Mexico', 'South Africa', 'South Korea', 'Czechia'],
  B: ['Canada', 'Bosnia and Herzegovina', 'Qatar', 'Switzerland'],
  C: ['Brazil', 'Morocco', 'Haiti', 'Scotland'],
  D: ['USA', 'Paraguay', 'Australia', 'Türkiye'],
  E: ['Germany', 'Curaçao', 'Ivory Coast', 'Ecuador'],
  F: ['Netherlands', 'Japan', 'Sweden', 'Tunisia'],
  G: ['Belgium', 'Egypt', 'Iran', 'New Zealand'],
  H: ['Spain', 'Cape Verde', 'Saudi Arabia', 'Uruguay'],
  I: ['France', 'Senegal', 'Iraq', 'Norway'],
  J: ['Argentina', 'Algeria', 'Austria', 'Jordan'],
  K: ['Portugal', 'DR Congo', 'Uzbekistan', 'Colombia'],
  L: ['England', 'Croatia', 'Ghana', 'Panama'],
};

const FLAGS = {
  USA: '🇺🇸', Mexico: '🇲🇽', Canada: '🇨🇦', Jamaica: '🇯🇲',
  England: '🏴󠁧󠁢󠁥󠁮󠁧󠁿', France: '🇫🇷', Belgium: '🇧🇪', Morocco: '🇲🇦',
  Argentina: '🇦🇷', Uruguay: '🇺🇾', Chile: '🇨🇱', Paraguay: '🇵🇾',
  Brazil: '🇧🇷', Colombia: '🇨🇴', Ecuador: '🇪🇨', Venezuela: '🇻🇪',
  Spain: '🇪🇸', Portugal: '🇵🇹', Germany: '🇩🇪', Switzerland: '🇨🇭',
  Netherlands: '🇳🇱', Croatia: '🇭🇷', Poland: '🇵🇱', 'Czech Republic': '🇨🇿',
  Japan: '🇯🇵', 'South Korea': '🇰🇷', Australia: '🇦🇺', 'Saudi Arabia': '🇸🇦',
  Nigeria: '🇳🇬', 'Ivory Coast': '🇨🇮', Senegal: '🇸🇳', Egypt: '🇪🇬',
  Iran: '🇮🇷', Iraq: '🇮🇶', Qatar: '🇶🇦', UAE: '🇦🇪',
  'New Zealand': '🇳🇿', Indonesia: '🇮🇩', 'South Africa': '🇿🇦', Tunisia: '🇹🇳',
  Peru: '🇵🇪', Bolivia: '🇧🇴', Panama: '🇵🇦', 'Costa Rica': '🇨🇷',
  Serbia: '🇷🇸', Hungary: '🇭🇺', Romania: '🇷🇴', Slovakia: '🇸🇰',
  TBD: '⬜',
};

const flag = () => '';

// ─── State helpers ────────────────────────────────────────────────────────────

const emptyKO = () => ({
  // R32: 32 slots = 16 matches
  r32: Array(32).fill('TBD'),
  // R16: 16 slots = 8 matches
  r16: Array(16).fill('TBD'),
  // QF: 8 slots = 4 matches
  qf: Array(8).fill('TBD'),
  // SF: 4 slots = 2 matches
  sf: Array(4).fill('TBD'),
  // Final: 2 slots = 1 match
  final: ['TBD', 'TBD'],
  // 3rd place: 2 slots = 1 match (auto-filled with SF losers)
  third: ['TBD', 'TBD'],
  winner: 'TBD',
  thirdPlace: 'TBD',
});

const emptyData = () => ({ qualifiers: {}, knockout: emptyKO() });

// ─── Shared components ────────────────────────────────────────────────────────

function MatchSlot({ teamA, teamB, label, onSelectWinner }) {
  return (
    <div className="match-slot">
      {label && <div className="match-label">{label}</div>}
      {[teamA, teamB].map((team, i) => (
        <div
          key={i}
          className={`match-team ${team !== 'TBD' && onSelectWinner ? 'clickable' : ''}`}
          style={{ borderTop: i === 1 ? '0.5px solid rgba(0,0,0,0.08)' : 'none' }}
          onClick={() => team !== 'TBD' && onSelectWinner && onSelectWinner(team)}
        >
          <span className="team-flag">{flag(team)}</span>
          {team === 'TBD'
            ? <span className="team-tbd">TBD</span>
            : <span className="team-name">{team}</span>}
        </div>
      ))}
    </div>
  );
}

// ─── Group Stage ──────────────────────────────────────────────────────────────

function GroupCard({ groupKey, teams, qualifiers, onToggle }) {
  const q = qualifiers[groupKey] || [];
  return (
    <div className="group-card">
      <div className="group-header">
        <span>Group {groupKey}</span>
        <span className="group-hint">tap to qualify</span>
      </div>
      <table className="group-table">
        <thead>
          <tr>
            <th></th>
            <th style={{ textAlign: 'left' }}>Team</th>
            <th>W</th><th>D</th><th>L</th><th>Pts</th>
          </tr>
        </thead>
        <tbody>
          {teams.map((team) => {
            const pos = q.indexOf(team);
            return (
              <tr
                key={team}
                className={`group-row pos-${pos}`}
                onClick={() => onToggle(groupKey, team)}
              >
                <td className="badge-cell">
                  {pos === 0 && <span className="badge b1">1st</span>}
                  {pos === 1 && <span className="badge b2">2nd</span>}
                  {pos === 2 && <span className="badge b3">3rd★</span>}
                </td>
                <td className="team-cell">
                  <span className="team-flag">{flag(team)}</span>
                  <span className="team-name">{team}</span>
                </td>
                <td>0</td><td>0</td><td>0</td>
                <td className="pts">0</td>
              </tr>
            );
          })}
        </tbody>
      </table>
    </div>
  );
}

function GroupStage({ data, onSetQualifiers, onBuildKnockout }) {
  const q = data.qualifiers;
  const allTop2Done = Object.keys(GROUPS).every((g) => (q[g] || []).length >= 2);
  const best3Count = Object.values(q).filter((v) => v && v[2]).length;
  const canBuild = allTop2Done && best3Count >= 8;

  const handleToggle = (groupKey, team) => {
    const cur = [...(q[groupKey] || [])];
    const idx = cur.indexOf(team);
    let next;
    if (idx >= 0) next = cur.filter((t) => t !== team);
    else if (cur.length < 3) next = [...cur, team];
    else next = [cur[1], cur[2], team];
    onSetQualifiers(groupKey, next);
  };

  return (
    <div>
      <div className="info-bar">
        Top 2 from each group (24 teams) + 8 best 3rd-place teams = 32 teams advance.
        Click once for 1st, twice for 2nd, three times for best-3rd ⭐, again to deselect.
      </div>
      <div className="group-grid">
        {Object.entries(GROUPS).map(([gk, teams]) => (
          <GroupCard
            key={gk}
            groupKey={gk}
            teams={teams}
            qualifiers={q}
            onToggle={handleToggle}
          />
        ))}
      </div>
      {allTop2Done && (
        <div className="build-row">
          {best3Count < 8 && (
            <p className="build-hint">
              {best3Count}/8 best 3rd-place teams selected. Pick {8 - best3Count} more.
            </p>
          )}
          <button
            className={`build-btn ${canBuild ? 'active' : 'disabled'}`}
            onClick={() => canBuild && onBuildKnockout()}
          >
            Build knockout bracket →
          </button>
        </div>
      )}
      {!allTop2Done && (
        <p className="build-hint">Select top 2 from every group to unlock the knockout stage.</p>
      )}
    </div>
  );
}

// ─── Knockout Stage ───────────────────────────────────────────────────────────

function KnockoutStage({ knockout, onUpdate }) {
  const ko = knockout;

  // Advance helpers
  const advR32 = (matchIdx, team) => {
    const r16 = [...ko.r16];
    r16[matchIdx] = team;
    onUpdate({ ...ko, r16 });
  };
  const advR16 = (matchIdx, team) => {
    const qf = [...ko.qf];
    qf[matchIdx] = team;
    onUpdate({ ...ko, qf });
  };
  const advQF = (matchIdx, team) => {
    const sf = [...ko.sf];
    sf[matchIdx] = team;
    onUpdate({ ...ko, sf });
  };
  const advSF = (matchIdx, team) => {
    // winner → final, loser → 3rd place playoff
    const sf = [...ko.sf];
    sf[matchIdx] = team;
    const otherIdx = matchIdx % 2 === 0 ? matchIdx + 1 : matchIdx - 1;
    const loser = [ko.sf[matchIdx], ko.sf[otherIdx]].find((t) => t !== team && t !== 'TBD') || 'TBD';
    const finalSlot = matchIdx < 2 ? 0 : 1;
    const thirdSlot = matchIdx < 2 ? 0 : 1;
    const final = [...ko.final];
    const third = [...ko.third];
    final[finalSlot] = team;
    third[thirdSlot] = loser;
    onUpdate({ ...ko, sf, final, third });
  };
  const advFinal = (team) => onUpdate({ ...ko, winner: team });
  const advThird = (team) => onUpdate({ ...ko, thirdPlace: team });

  // Match height for spacing calculations
  const matchH = 80; // approximate px height of one match slot
  const gap0 = 6;    // R32 gap between matches
  const gap1 = (matchH + gap0) * 2 - matchH; // R16
  const gap2 = (matchH + gap1) * 2 - matchH; // QF
  const gap3 = (matchH + gap2) * 2 - matchH; // SF

  const mt1 = (matchH + gap0) / 2;
  const mt2 = mt1 + (matchH + gap1) / 2;
  const mt3 = mt2 + (matchH + gap2) / 2;
  const mt4 = mt3 + (matchH + gap3) / 2;

  function renderColumn(label, matches, marginTop, colorClass = '') {
    return (
      <div className={`ko-col ${colorClass}`}>
        <div className="ko-col-label">{label}</div>
        <div className="ko-col-matches" style={{ marginTop }}>
          {matches.map((m, i) => (
            <div key={i}>
              {i > 0 && <div style={{ height: m.gap }} />}
              {m.node}
            </div>
          ))}
        </div>
      </div>
    );
  }

  // Build match lists
  const r32Left = Array.from({ length: 8 }, (_, i) => ({
    node: <MatchSlot teamA={ko.r32[i * 2]} teamB={ko.r32[i * 2 + 1]} label={`R32 ${i + 1}`} onSelectWinner={(t) => advR32(i, t)} />,
    gap: gap0,
  }));
  const r32Right = Array.from({ length: 8 }, (_, i) => {
    const mi = i + 8;
    return {
      node: <MatchSlot teamA={ko.r32[mi * 2]} teamB={ko.r32[mi * 2 + 1]} label={`R32 ${mi + 1}`} onSelectWinner={(t) => advR32(mi, t)} />,
      gap: gap0,
    };
  });
  const r16Left = Array.from({ length: 4 }, (_, i) => ({
    node: <MatchSlot teamA={ko.r16[i * 2]} teamB={ko.r16[i * 2 + 1]} label={`R16 ${i + 1}`} onSelectWinner={(t) => advR16(i, t)} />,
    gap: gap1,
  }));
  const r16Right = Array.from({ length: 4 }, (_, i) => {
    const mi = i + 4;
    return {
      node: <MatchSlot teamA={ko.r16[mi * 2]} teamB={ko.r16[mi * 2 + 1]} label={`R16 ${mi + 1}`} onSelectWinner={(t) => advR16(mi, t)} />,
      gap: gap1,
    };
  });
  const qfLeft = Array.from({ length: 2 }, (_, i) => ({
    node: <MatchSlot teamA={ko.qf[i * 2]} teamB={ko.qf[i * 2 + 1]} label={`QF ${i + 1}`} onSelectWinner={(t) => advQF(i, t)} />,
    gap: gap2,
  }));
  const qfRight = Array.from({ length: 2 }, (_, i) => {
    const mi = i + 2;
    return {
      node: <MatchSlot teamA={ko.qf[mi * 2]} teamB={ko.qf[mi * 2 + 1]} label={`QF ${mi + 1}`} onSelectWinner={(t) => advQF(mi, t)} />,
      gap: gap2,
    };
  });

  return (
    <div>
      <p className="ko-hint">Click a team to advance them. SF losers auto-fill the 3rd place playoff.</p>
      <div className="ko-scroll">
        <div className="ko-bracket">
          {/* Left half */}
          {renderColumn('Round of 32', r32Left, 0)}
          {renderColumn('Round of 16', r16Left, mt1)}
          {renderColumn('Quarter-finals', qfLeft, mt2)}
          {renderColumn('Semi-finals', [{ node: <MatchSlot teamA={ko.sf[0]} teamB={ko.sf[1]} label="SF 1" onSelectWinner={(t) => advSF(0, t)} />, gap: 0 }], mt3)}

          {/* Centre column */}
          <div className="ko-col ko-centre">
            <div style={{ height: mt4 }} />
            <div className="ko-col-label">Final</div>
            <MatchSlot teamA={ko.final[0]} teamB={ko.final[1]} label="🏆 Final" onSelectWinner={advFinal} />
            <div className="champion-box">
              <div className="champ-trophy">🏆</div>
              <div className="champ-label">CHAMPION</div>
              <div className="champ-team">
                <span>{flag(ko.winner)}</span>
                <span>{ko.winner === 'TBD' ? <em>TBD</em> : ko.winner}</span>
              </div>
            </div>
            <div style={{ height: 20 }} />
            <div className="ko-col-label third-label">3rd Place</div>
            <MatchSlot teamA={ko.third[0]} teamB={ko.third[1]} label="🥉 3rd place" onSelectWinner={advThird} />
            {ko.thirdPlace !== 'TBD' && (
              <div className="third-box">
                <div className="champ-trophy">🥉</div>
                <div className="champ-label">3RD PLACE</div>
                <div className="champ-team">
                  <span>{flag(ko.thirdPlace)}</span>
                  <span>{ko.thirdPlace}</span>
                </div>
              </div>
            )}
          </div>

          {/* Right half */}
          {renderColumn('Semi-finals', [{ node: <MatchSlot teamA={ko.sf[2]} teamB={ko.sf[3]} label="SF 2" onSelectWinner={(t) => advSF(2, t)} />, gap: 0 }], mt3)}
          {renderColumn('Quarter-finals', qfRight, mt2)}
          {renderColumn('Round of 16', r16Right, mt1)}
          {renderColumn('Round of 32', r32Right, 0)}
        </div>
      </div>

      {/* Summary banner */}
      {(ko.winner !== 'TBD' || ko.thirdPlace !== 'TBD') && (
        <div className="result-banner">
          {ko.winner !== 'TBD' && (
            <div className="result-item">
              <span>🏆</span>
              <div>
                <div className="result-label">CHAMPION</div>
                <div className="result-team"><span>{flag(ko.winner)}</span> {ko.winner}</div>
              </div>
            </div>
          )}
          {ko.thirdPlace !== 'TBD' && (
            <div className="result-item">
              <span>🥉</span>
              <div>
                <div className="result-label">3RD PLACE</div>
                <div className="result-team"><span>{flag(ko.thirdPlace)}</span> {ko.thirdPlace}</div>
              </div>
            </div>
          )}
        </div>
      )}
    </div>
  );
}

// ─── App ──────────────────────────────────────────────────────────────────────

export default function App() {
  const [activeTab, setActiveTab] = useState('prediction');
  const [section, setSection] = useState('groups');
  const [prediction, setPrediction] = useState(emptyData());
  const [actual, setActual] = useState(emptyData());

  const data = activeTab === 'prediction' ? prediction : actual;
  const setDataFn = activeTab === 'prediction' ? setPrediction : setActual;

  const setQualifiers = (groupKey, teams) => {
    setDataFn((prev) => ({
      ...prev,
      qualifiers: { ...prev.qualifiers, [groupKey]: teams },
    }));
  };

  const buildKnockout = () => {
    const q = data.qualifiers;
    const p = (g, i) => (q[g] || [])[i] || 'TBD';
    // 24 group qualifiers: 1st + 2nd from each of 12 groups
    const slots = [];
    'ABCDEFGHIJKL'.split('').forEach((g) => { slots.push(p(g, 0)); slots.push(p(g, 1)); });
    // 8 best 3rd-place teams
    const thirds = [];
    'ABCDEFGHIJKL'.split('').forEach((g) => { if ((q[g] || [])[2]) thirds.push(q[g][2]); });
    while (thirds.length < 8) thirds.push('TBD');
    const r32 = [...slots, ...thirds.slice(0, 8)];
    while (r32.length < 32) r32.push('TBD');
    setDataFn((prev) => ({ ...prev, knockout: { ...emptyKO(), r32 } }));
    setSection('knockout');
  };

  const updateKnockout = (ko) => setDataFn((prev) => ({ ...prev, knockout: ko }));

  return (
    <div className="app">
      {/* Header */}
      <div className="hero">
        <span className="hero-icon">⚽</span>
        <div>
          <div className="hero-title">FIFA World Cup 2026</div>
          <div className="hero-sub">48 teams · 12 groups · R32 → R16 → QF → SF → Final + 3rd place</div>
        </div>
      </div>

      {/* Tab switcher */}
      <div className="tab-row">
        {[
          { id: 'prediction', label: '🔮 My Prediction', color: '#1a3c5e' },
          { id: 'actual',     label: '📺 Actual Results', color: '#6b1a1a' },
        ].map((t) => (
          <button
            key={t.id}
            className="tab-btn"
            style={{ background: activeTab === t.id ? t.color : '#fff', color: activeTab === t.id ? '#fff' : '#666' }}
            onClick={() => setActiveTab(t.id)}
          >
            {t.label}
          </button>
        ))}
      </div>

      {/* Section nav */}
      <div className="section-nav">
        {[
          { id: 'groups',   label: 'Group Stage' },
          { id: 'knockout', label: 'Knockout Stage' },
        ].map((s) => (
          <button
            key={s.id}
            className={`section-btn ${section === s.id ? 'active' : ''}`}
            onClick={() => setSection(s.id)}
          >
            {s.label}
          </button>
        ))}
      </div>

      {/* Content */}
      <div className="content">
        {section === 'groups' && (
          <GroupStage
            data={data}
            onSetQualifiers={setQualifiers}
            onBuildKnockout={buildKnockout}
          />
        )}
        {section === 'knockout' && (
          <KnockoutStage
            knockout={data.knockout}
            onUpdate={updateKnockout}
          />
        )}
      </div>
    </div>
  );
}
